import datetime

most_recent_observations = {}

for code in code_list:
    observations = apis.fhir.search_observation(
        patient_id=patient_id,
        code=code
    )

    # Filter and sort observations by effective date (descending)
    valid_obs = []
    for obs in observations:
        date_str = obs.get('effectiveDateTime')
        if date_str:
            try:
                parsed_date = datetime.datetime.fromisoformat(date_str)
                valid_obs.append((parsed_date, obs))
            except ValueError:
                continue

    if valid_obs:
        # Sort by date descending and take the most recent
        valid_obs.sort(key=lambda x: x[0], reverse=True)
        most_recent_observations[code] = valid_obs[0][1]
    else:
        most_recent_observations[code] = None

